public void testSingleLineNoNewLine() throws Exception {
  // Test single line file without trailing newline
  SimpleSourceExcerptProvider provider = new SimpleSourceExcerptProvider();
  provider.addSourceCode("single", "only one line");
  assertEquals("single:only one line", provider.getSourceLine("single", 1));
  assertEquals(null, provider.getSourceLine("single", 2));
}

public void testEmptyLastLine() throws Exception {
  // Test file ending with newline (empty last line)
  SimpleSourceExcerptProvider provider = new SimpleSourceExcerptProvider();
  provider.addSourceCode("emptyEnd", "line1\nline2\n");
  assertEquals("emptyEnd:line1", provider.getSourceLine("emptyEnd", 1));
  assertEquals("emptyEnd:line2", provider.getSourceLine("emptyEnd", 2));
  assertEquals(null, provider.getSourceLine("emptyEnd", 3));
}

public void testMultipleLinesLastNoNewLine() throws Exception {
  // Test multiple lines where last line has no trailing newline
  SimpleSourceExcerptProvider provider = new SimpleSourceExcerptProvider();
  provider.addSourceCode("multi", "first\nsecond\nthird");
  assertEquals("multi:first", provider.getSourceLine("multi", 1));
  assertEquals("multi:second", provider.getSourceLine("multi", 2));
  assertEquals("multi:third", provider.getSourceLine("multi", 3));
  assertEquals(null, provider.getSourceLine("multi", 4));
}
